#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int cnt[1440]; memset(cnt,0,sizeof(cnt));
        int A[N];
        for(int i=0;i<N;i++) scanf("%d",&A[i]);
        for(int i=0;i<N;i++){
            int d; scanf("%d",&d);
            cnt[A[i]]++;
            cnt[d]++;
        }
        int ans=0;
        for(int i=0;i<1440;i++) if(cnt[i]>ans) ans=cnt[i];
        printf("%d\n",ans);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> A(N);
        for(int &x: A) cin>>x;
        int cnt[1440] = {0};
        for(int i=0;i<N;i++){
            int d; cin>>d;
            ++cnt[A[i]];
            ++cnt[d];
        }
        int ans=0;
        for(int v: cnt) ans=max(ans,v);
        cout<<ans<<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] A = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) A[i] = Integer.parseInt(st.nextToken());
            int[] cnt = new int[1440];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) {
                int d = Integer.parseInt(st.nextToken());
                cnt[A[i]]++;
                cnt[d]++;
            }
            int ans = 0;
            for (int v : cnt) if (v > ans) ans = v;
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

